/* src/storage.js */
const TAB_PLAYER_PREFIX = "room-rush-player:";
const SAVED_PLAYER_PREFIX = "atwix-player:";
const LAST_ROOM_KEY = "atwix-last-room";

const partyLines = [
  "Leaderboard drama incoming.",
  "Protect your streak.",
  "Fast fingers, big points.",
  "No pressure, but everyone is watching.",
  "Wrong answers build character.",
  "The group chat will remember this."
];

async function createRoom() {
  const result = await api("/api/rooms", {
    method: "POST"
  });
  setTabPlayerId(result.room.code, result.player.id);
  return result;
}

async function joinRoom(codeInput) {
  const code = normalizeCode(codeInput);
  const result = await api(`/api/rooms/${code}/join`, {
    method: "POST"
  });
  setTabPlayerId(result.room.code, result.player.id);
  return result;
}

async function readRoom(codeInput) {
  const code = normalizeCode(codeInput);
  if (!code) return null;
  try {
    return (await api(`/api/rooms/${code}`)).room;
  } catch {
    return null;
  }
}

async function updateSettings(code, playerId, settings) {
  return (await api(`/api/rooms/${normalizeCode(code)}/settings`, {
    method: "POST",
    body: { playerId, settings }
  })).room;
}

async function setLobbyReady(code, playerId, ready) {
  return (await api(`/api/rooms/${normalizeCode(code)}/lobby-ready`, {
    method: "POST",
    body: { playerId, ready }
  })).room;
}

async function transferHost(code, playerId, targetPlayerId = playerId) {
  return (await api(`/api/rooms/${normalizeCode(code)}/transfer-host`, {
    method: "POST",
    body: { playerId, targetPlayerId }
  })).room;
}

async function startGame(code, playerId) {
  return (await api(`/api/rooms/${normalizeCode(code)}/start`, {
    method: "POST",
    body: { playerId }
  })).room;
}

async function submitAnswer(code, playerId, choiceIndex) {
  return (await api(`/api/rooms/${normalizeCode(code)}/answer`, {
    method: "POST",
    body: { playerId, choiceIndex }
  })).room;
}

async function tickRoom(code) {
  return (await api(`/api/rooms/${normalizeCode(code)}/tick`, { method: "POST" })).room;
}

async function showLeaderboard(code, playerId) {
  return (await api(`/api/rooms/${normalizeCode(code)}/show-leaderboard`, {
    method: "POST",
    body: { playerId }
  })).room;
}

async function nextQuestion(code, playerId) {
  return (await api(`/api/rooms/${normalizeCode(code)}/next`, {
    method: "POST",
    body: { playerId }
  })).room;
}

async function reportQuestion(code, playerId, questionId, reason) {
  return (await api(`/api/rooms/${normalizeCode(code)}/report-question`, {
    method: "POST",
    body: { playerId, questionId, reason }
  })).room;
}

async function leaveRoom(code, playerId) {
  const normalized = normalizeCode(code);
  const room = (await api(
    "/api/rooms/" + normalized + "/leave",
    {
      method: "POST",
      body: { playerId }
    }
  )).room;
  clearSavedPlayerId(normalized);
  return room;
}

async function playAgain(code, playerId) {
  return (await api(`/api/rooms/${normalizeCode(code)}/play-again`, {
    method: "POST",
    body: { playerId }
  })).room;
}

function subscribeToRoom(code, playerId, callback, onStatus = () => {}) {
  const normalized = normalizeCode(code);
  if (!("EventSource" in window)) return () => {};

  const query = playerId ? `?player=${encodeURIComponent(playerId)}` : "";
  const source = new EventSource(`/api/rooms/${normalized}/events${query}`);
  source.onopen = () => onStatus("live");
  source.addEventListener("room", (event) => callback(JSON.parse(event.data)));
  source.onerror = () => onStatus("reconnecting");
  return () => source.close();
}

function recoverPlayer(room, preferredPlayerId = null) {
  if (!room) return null;
  if (preferredPlayerId) {
    const preferred = room.players.find((player) => player.id === preferredPlayerId);
    if (preferred) return preferred;
  }
  const id = getTabPlayerId(room.code);
  return room.players.find((player) => player.id === id) || null;
}

function getCurrentQuestionId(room) {
  return room?.selectedQuestionIds?.[room.currentRoundIndex] || null;
}

function getCurrentAnswer(room, playerId) {
  const questionId = getCurrentQuestionId(room);
  return questionId ? room.answers?.[questionId]?.[playerId] || null : null;
}

function getRoundResult(room) {
  return room?.roundResults?.[room.currentRoundIndex] || null;
}

function getPlayerResult(room, playerId) {
  return getRoundResult(room)?.playerResults?.find((result) => result.playerId === playerId) || null;
}

async function api(path, options = {}) {
  const response = await fetch(path, {
    method: options.method || "GET",
    headers: options.body ? { "Content-Type": "application/json" } : undefined,
    body: options.body ? JSON.stringify(options.body) : undefined
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(payload.error || "The room server did not respond.");
  return payload;
}

function normalizeCode(value) {
  return String(value || "").trim().toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 5);
}

function getTabPlayerId(code) {
  return sessionStorage.getItem(`${TAB_PLAYER_PREFIX}${code}`) || localStorage.getItem(`${SAVED_PLAYER_PREFIX}${code}`);
}

function setTabPlayerId(code, playerId) {
  sessionStorage.setItem(`${TAB_PLAYER_PREFIX}${code}`, playerId);
  localStorage.setItem(`${SAVED_PLAYER_PREFIX}${code}`, playerId);
  localStorage.setItem(LAST_ROOM_KEY, code);
}

function clearSavedPlayerId(code) {
  sessionStorage.removeItem(`${TAB_PLAYER_PREFIX}${code}`);
  localStorage.removeItem(`${SAVED_PLAYER_PREFIX}${code}`);
  if (localStorage.getItem(LAST_ROOM_KEY) === code) localStorage.removeItem(LAST_ROOM_KEY);
}

function getSavedRoomCode() {
  return localStorage.getItem(LAST_ROOM_KEY) || "";
}


/* src/app.js */

const app = document.querySelector("#app");
const toast = document.querySelector("#toast");
const params = new URLSearchParams(window.location.search);

let state = {
  account: null,
  accountSummary: null,
  authChecked: false,
  authView: params.get("auth") === "reset" ? "reset-password" : "sign-in",
  authMessage: "",
  view: "landing",
  room: null,
  currentPlayer: null,
  playerId: params.get("player") || "",
  joinCode: params.get("room") || "",
  createName: "",
  createMode: "Classic",
  joinName: "",
  error: "",
  loading: false,
  unsubscribe: null,
  timer: null,
	  localChoices: new Map(),
	  pendingAnswerKey: "",
	  audioEvents: new Set(),
	  connection: "idle",
	  installPrompt: null,
  canInstall: false,
  installDismissed: localStorage.getItem("room-rush-install-dismissed") === "true"
};

boot();
window.addEventListener("pagehide", stopAllAudio);
window.addEventListener("beforeunload", stopAllAudio);
window.addEventListener("beforeinstallprompt", (event) => {
  event.preventDefault();
  state.installPrompt = event;
  state.canInstall = true;
  state.installDismissed = false;
  render();
});
window.addEventListener("appinstalled", () => {
  state.installPrompt = null;
  state.canInstall = false;
  state.installDismissed = true;
  localStorage.setItem("room-rush-install-dismissed", "true");
  showToast("Installed. Ready from your home screen.");
  render();
});

async function boot() {
  registerServiceWorker();
  await consumeAuthCallback();
  try {
    const session = await readSession();
    state.account = session.account;
    state.playerId = state.account?.id || "";
  } catch {
    state.account = null;
  }
  state.authChecked = true;

  if (state.account && state.joinCode) {
    const room = await readRoom(state.joinCode);
    if (room) {
      state.room = room;
      state.currentPlayer = recoverPlayer(room, state.playerId);
      state.view = state.currentPlayer ? "room" : "join";
      connectRoom(room.code);
    } else {
      state.view = "join";
      state.error = "We could not find that room. Check the code and try again.";
    }
  }
  render();
}

function render() {
  app.innerHTML = screenLayout(renderCurrentView());
  bindActions();
}

function renderCurrentView() {
  if (!state.authChecked) return renderAuthLoading();
  if (state.authView === "reset-password") return renderResetPassword();
  if (!state.account) return renderAuth();
  if (state.view === "profile") return renderProfile();
  if (state.view === "create") return renderCreate();
  if (state.view === "join") return renderJoin();
  if (!state.room || !state.currentPlayer) return renderLanding();
  if (state.room.status === "lobby") return renderLobby();
  if (state.room.status === "question") {
    return Date.now() < state.room.currentQuestionStartedAt ? renderCountdown() : renderQuestion();
  }
  if (state.room.status === "reveal") return renderReveal();
  if (state.room.status === "leaderboard") return renderLeaderboard();
  if (state.room.status === "finished") return renderFinal();
  return renderLanding();
}

function screenLayout(content) {
  const genius = isGeniusMode();
  return `
    <section class="screen ${genius ? "genius-mode" : ""}">
	      <div class="rush-strip" aria-hidden="true">
	        <span>Atwix</span>
	        <span>${genius ? "Genius Gauntlet" : "Fast fingers"}</span>
	        <span>${genius ? "Six domains · one crown" : "Big points"}</span>
	      </div>
	      ${renderAudioControls()}
	      ${state.account ? renderAccountBar() : ""}
	      ${renderConnectionStatus()}
	      ${state.error ? `<div class="error-banner"><strong>${escapeHtml(getPhrase("errorHelper", state.error))}</strong><span>${escapeHtml(state.error)}</span></div>` : ""}
	      ${content}
	    </section>
	  `;
	}

function renderAuthLoading() {
  return `<section class="auth-shell"><p class="eyebrow">Atwix accounts</p><h2>Loading your arena…</h2></section>`;
}

function renderAuth() {
  if (state.authView === "sign-up") return renderSignUp();
  if (state.authView === "forgot") return renderForgotPassword();
  if (state.authView === "reset-password") return renderResetPassword();
  if (state.authView === "check-email") return renderCheckEmail();
  return renderSignIn();
}

function renderSignIn() {
  return `
    <section class="auth-shell">
      <p class="eyebrow">Account required</p>
      <h1>Welcome back.</h1>
      <p class="subtitle">Sign in to play, protect your record, and continue every rivalry.</p>
      ${state.authMessage ? `<p class="inline-note">${escapeHtml(state.authMessage)}</p>` : ""}
      <form class="panel form-panel" id="sign-in-form">
        <label><span>Email</span><input name="email" type="email" autocomplete="email" required /></label>
        <label><span>Password</span><input name="password" type="password" autocomplete="current-password" required /></label>
        <button class="primary-button wide" type="submit" ${state.loading ? "disabled" : ""}>Sign In</button>
      </form>
      <div class="auth-links">
        <button class="ghost-button" data-auth-view="forgot">Forgot password?</button>
        <button class="secondary-button" data-auth-view="sign-up">Create an account</button>
      </div>
    </section>`;
}

function renderSignUp() {
  return `
    <section class="auth-shell">
      <p class="eyebrow">Join the history books</p>
      <h1>Create account.</h1>
      <p class="subtitle">Your email stays private. Rivals only see your display name and match record.</p>
      <form class="panel form-panel" id="sign-up-form">
        <label><span>Display name</span><input name="displayName" maxlength="28" autocomplete="nickname" placeholder="Mira" required /></label>
        <label><span>Email</span><input name="email" type="email" autocomplete="email" required /></label>
        <label><span>Password</span><input name="password" type="password" minlength="8" autocomplete="new-password" required /></label>
        <button class="primary-button wide" type="submit" ${state.loading ? "disabled" : ""}>Create Account</button>
      </form>
      <button class="ghost-button wide" data-auth-view="sign-in">Already have an account? Sign in</button>
    </section>`;
}

function renderForgotPassword() {
  return `
    <section class="auth-shell">
      <p class="eyebrow">Password recovery</p>
      <h2>Get a reset link.</h2>
      <form class="panel form-panel" id="forgot-form">
        <label><span>Email</span><input name="email" type="email" autocomplete="email" required /></label>
        <button class="primary-button wide" type="submit">Send Reset Email</button>
      </form>
      <button class="ghost-button wide" data-auth-view="sign-in">Back to sign in</button>
    </section>`;
}

function renderResetPassword() {
  return `
    <section class="auth-shell">
      <p class="eyebrow">Choose a new password</p>
      <h2>Secure your account.</h2>
      <form class="panel form-panel" id="reset-password-form">
        <label><span>New password</span><input name="password" type="password" minlength="8" autocomplete="new-password" required /></label>
        <button class="primary-button wide" type="submit">Update Password</button>
      </form>
    </section>`;
}

function renderCheckEmail() {
  return `
    <section class="auth-shell">
      <p class="eyebrow">One final step</p>
      <h1>Check your email.</h1>
      <p class="subtitle">Open the confirmation link, then Atwix will sign you in and begin keeping your history.</p>
      <button class="secondary-button wide" data-auth-view="sign-in">Back to Sign In</button>
    </section>`;
}

function renderAccountBar() {
  return `
    <nav class="account-bar" aria-label="Account">
      <button class="account-identity" data-view="profile"><span>${escapeHtml(state.account.displayName)}</span><small>${state.account.totalWins} wins · ${state.account.totalLosses} losses</small></button>
      <button class="ghost-button" id="sign-out">Sign Out</button>
    </nav>`;
}

function renderConnectionStatus() {
  if (!state.room || state.connection === "idle") return "";
  const label = state.connection === "live" ? "Connected" : "Reconnecting";
  return `<div class="connection-pill ${state.connection}">${label}</div>`;
}

function renderAudioControls() {
  const audio = getAudioSettings();
  return `
    <section class="audio-controls" aria-label="Audio controls">
      <button class="audio-button" id="sound-toggle" type="button">
        ${audio.unlocked && audio.soundOn ? "🔊 Sound On" : audio.unlocked ? "🔇 Sound Off" : "Enable party sounds"}
      </button>
      ${audio.unlocked ? `
        <button class="audio-button" id="music-toggle" type="button">${audio.musicOn ? "🎵 Music On" : "Music Off"}</button>
        <label class="volume-control">
          <span>Volume</span>
          <input id="volume-slider" type="range" min="0" max="1" step="0.05" value="${audio.volume}" />
        </label>
      ` : ""}
    </section>
  `;
}

function renderLanding() {
  return `
    <section class="hero-panel">
      <p class="eyebrow">Party trivia for fast friends.</p>
      <h1>Atwix Trivia</h1>
      <p class="subtitle">${escapeHtml(getPhrase("landingSubtitle", "home"))}</p>
      <p class="signed-in-note">Playing as <strong>${escapeHtml(state.account.displayName)}</strong>. Every completed game now counts.</p>
      <div class="mode-launch-grid">
        <button class="mode-launch genius-launch" data-view="create" data-create-mode="Genius">
          <span class="mode-launch-badge">New · Expert challenge</span>
          <strong>Genius Mode</strong>
          <small>6 sections · 30 difficult questions · double points</small>
        </button>
        <button class="mode-launch classic-launch" data-view="create" data-create-mode="Classic">
          <span class="mode-launch-badge">Party favorite</span>
          <strong>Classic Game</strong>
          <small>Choose your rounds, pacing, and category</small>
        </button>
      </div>
      <button class="secondary-button landing-join" data-view="join">Join a Room</button>
      <p class="helper">${escapeHtml(getPhrase("landingHelper", "home"))}</p>
    </section>
    ${renderInstallCard()}
  `;
}

function renderCreate() {
  const genius = state.createMode === "Genius";
  return `
    <div class="topbar">
      <button class="ghost-button icon-button" data-view="landing" aria-label="Back">‹</button>
      <div>
        <p class="eyebrow">${genius ? "Genius mode" : "Classic game"}</p>
        <h2>${genius ? "Build the gauntlet." : "Start the room."}</h2>
      </div>
    </div>
    <form class="panel form-panel" id="create-form">
      <fieldset class="create-mode-picker">
        <legend>Choose game mode</legend>
        <label class="create-mode-option ${genius ? "selected genius-option" : "genius-option"}">
          <input type="radio" name="gameMode" value="Genius" ${genius ? "checked" : ""} />
          <span><strong>Genius</strong><small>Six expert sections, 30 questions, double points</small></span>
        </label>
        <label class="create-mode-option ${!genius ? "selected" : ""}">
          <input type="radio" name="gameMode" value="Classic" ${!genius ? "checked" : ""} />
          <span><strong>Classic</strong><small>Flexible party trivia with custom categories</small></span>
        </label>
      </fieldset>
      <p class="identity-lock">Host account: <strong>${escapeHtml(state.account.displayName)}</strong></p>
      <button class="primary-button wide ${genius ? "genius-create-button" : ""}" type="submit" ${state.loading ? "disabled" : ""}>${genius ? "Create Genius Room" : "Create Classic Room"}</button>
    </form>
  `;
}

function renderJoin() {
  const roomIsFull = state.room && state.room.players.length >= 12 && !recoverPlayer(state.room, state.playerId);
  return `
    <div class="topbar">
      <button class="ghost-button icon-button" data-view="landing" aria-label="Back">‹</button>
      <div>
        <p class="eyebrow">Join game</p>
        <h2>${roomIsFull ? "Room is full." : "Enter the rush."}</h2>
      </div>
    </div>
    ${state.room && !roomIsFull ? `<p class="inline-note">Joining room <strong>${escapeHtml(state.room.code)}</strong>. ${escapeHtml(getPhrase("lobbyHelper", `join:${state.room.code}`))}</p>` : ""}
    <form class="panel form-panel" id="join-form">
      <p class="identity-lock">Joining as <strong>${escapeHtml(state.account.displayName)}</strong></p>
      <label>
        <span>Room code</span>
        <input name="roomCode" class="code-input" maxlength="5" placeholder="A8K2P" value="${escapeAttr(state.joinCode)}" ${roomIsFull ? "disabled" : "required"} />
      </label>
      <button class="primary-button wide" type="submit" ${state.loading || roomIsFull ? "disabled" : ""}>Join Game</button>
    </form>
  `;
}

function renderLobby() {
  const isHost = isCurrentHost();
  const genius = isGeniusMode();
  const ready = state.room.lobbyReady || {};
  const currentReady = Boolean(ready[state.currentPlayer.id]);
  const readyCount = state.room.players.filter((player) => ready[player.id]).length;
  const allReady = state.room.players.length >= 2 && readyCount === state.room.players.length;
  const hostOnline = isPlayerOnline(state.room.hostId);
  const canClaimHost = !isHost && !hostOnline;
  return `
    <div class="topbar">
      <div>
        <p class="eyebrow">Room ${state.room.code}</p>
        <h2>${state.room.players.length < 2 ? "Invite friends." : "Ready when you are."}</h2>
      </div>
      <button class="ghost-button" data-copy="${escapeAttr(state.room.inviteUrl)}">Copy Link</button>
    </div>
    ${renderInstallCard("lobby")}
    <section class="panel room-card invite-card">
      <div>
        <p class="eyebrow">Invite screen</p>
        <h3>Share this with your brothers.</h3>
        <p class="helper">The link opens this exact room on any phone or laptop.</p>
      </div>
      <div class="room-code-block">
        <span>Room code</span>
        <strong>${state.room.code}</strong>
      </div>
      <div class="share-row">
        <button class="primary-button" id="share-button">Share with brothers</button>
        <button class="secondary-button" data-copy="${escapeAttr(state.room.inviteUrl)}">Copy invite link</button>
      </div>
    </section>
    <section class="panel">
      <div class="section-title">
        <h3>Players</h3>
        <span>${readyCount}/${state.room.players.length} ready</span>
      </div>
      <div class="player-list">
        ${state.room.players.map((player) => `
          <div class="player-pill">
            <span>${escapeHtml(player.displayName)}${player.id === state.currentPlayer.id ? " <small>You</small>" : ""}</span>
            <span class="pill-actions">
              ${isPlayerOnline(player.id) ? `<small>Online</small>` : `<small>Offline</small>`}
              ${ready[player.id] ? `<strong>Ready</strong>` : `<strong>Not yet</strong>`}
              ${player.id === state.room.hostId ? `<strong>Host</strong>` : ""}
              ${isHost && player.id !== state.currentPlayer.id ? `<button class="mini-button" data-transfer-host="${escapeAttr(player.id)}">Make host</button>` : ""}
            </span>
          </div>
        `).join("")}
      </div>
      <div class="lobby-actions">
        <button class="${currentReady ? "secondary-button" : "primary-button"} wide" id="lobby-ready">${currentReady ? "Ready locked" : "I'm Ready"}</button>
        ${canClaimHost ? `<button class="secondary-button wide" id="claim-host">Become Host</button>` : ""}
      </div>
      ${!hostOnline && !isHost ? `<p class="inline-note">The host looks offline. You can become host and keep the room moving.</p>` : ""}
    </section>
    <section class="panel">
      <div class="section-title">
        <h3>Game setup</h3>
        <span>${isHost ? allReady ? "Ready to start" : "Waiting for ready" : "Waiting"}</span>
      </div>
      ${isHost ? renderSettingsForm() : `<p class="helper">${escapeHtml(getPhrase("waitingForHost", state.room.code))}</p>`}
    </section>
    ${renderRoomRivalries()}
    ${genius ? `
      <section class="genius-brief">
        <p class="eyebrow">Genius mode armed</p>
        <h3>Six sections. Thirty hard questions. No filler.</h3>
        <div class="genius-category-list">
          ${GENIUS_CATEGORIES.map((category, index) => `<span><b>${index + 1}</b>${escapeHtml(category)}</span>`).join("")}
        </div>
        <p>Each section draws five questions from a private bank of 110. Correct answers are worth double before speed and streak bonuses.</p>
      </section>
    ` : ""}
  `;
}

function renderRoomRivalries() {
  const records = state.room?.rivalries || [];
  if (!records.length) {
    return state.room?.players?.length > 1
      ? `<section class="panel rivalry-panel"><div class="section-title"><h3>Rivalry history</h3><span>First meeting</span></div><p class="helper">No previous results between these accounts. Tonight starts the record.</p></section>`
      : "";
  }
  return `
    <section class="panel rivalry-panel">
      <div class="section-title"><h3>Rivalry history</h3><span>Permanent record</span></div>
      <div class="rivalry-list">${records.map(renderRivalryCard).join("")}</div>
    </section>`;
}

function renderRivalryCard(record) {
  const lowLeads = record.lowWins > record.highWins;
  const highLeads = record.highWins > record.lowWins;
  const headline = lowLeads
    ? `${record.lowName} leads ${record.highName}`
    : highLeads
      ? `${record.highName} leads ${record.lowName}`
      : `${record.lowName} and ${record.highName} are level`;
  const streakName = record.streakWinnerId === record.accountLow ? record.lowName : record.streakWinnerId === record.accountHigh ? record.highName : "";
  return `
    <article class="rivalry-card">
      <div><strong>${escapeHtml(headline)}</strong><span>${record.lowWins}–${record.highWins}${record.draws ? ` · ${record.draws} draw${record.draws === 1 ? "" : "s"}` : ""}</span></div>
      ${streakName && record.streakCount > 1 ? `<small>${escapeHtml(streakName)} has won ${record.streakCount} straight</small>` : `<small>${record.lastPlayedAt ? `Last played ${escapeHtml(formatHistoryDate(record.lastPlayedAt))}` : "History begins now"}</small>`}
    </article>`;
}

function renderProfile() {
  const account = state.accountSummary?.account || state.account;
  const rivalries = state.accountSummary?.rivalries || [];
  const winRate = account.totalGames ? Math.round((account.totalWins / account.totalGames) * 100) : 0;
  return `
    <div class="topbar"><button class="ghost-button icon-button" data-view="landing" aria-label="Back">‹</button><div><p class="eyebrow">Career record</p><h2>${escapeHtml(account.displayName)}</h2></div></div>
    <section class="profile-hero">
      <div><span>Games</span><strong>${account.totalGames}</strong></div>
      <div><span>Wins</span><strong>${account.totalWins}</strong></div>
      <div><span>Losses</span><strong>${account.totalLosses}</strong></div>
      <div><span>Win rate</span><strong>${winRate}%</strong></div>
    </section>
    <section class="panel"><div class="section-title"><h3>Mode trophies</h3><span>${account.totalDraws} draws</span></div><div class="points-list"><div><span>Classic wins</span><strong>${account.classicWins}</strong></div><div><span>Genius wins</span><strong>${account.geniusWins}</strong></div></div></section>
    <section class="panel"><div class="section-title"><h3>Your rivalries</h3><span>${rivalries.length}</span></div>${rivalries.length ? `<div class="rivalry-list">${rivalries.map(renderRivalryCard).join("")}</div>` : `<p class="helper">Complete a game against another account to begin a rivalry.</p>`}</section>`;
}

function renderSettingsForm() {
  const genius = isGeniusMode();
  return `
    <form id="settings-form" class="settings-grid">
      <label class="wide-field">
        <span>Game mode</span>
        <select name="gameMode">
          <option value="Classic" ${!genius ? "selected" : ""}>Classic Party</option>
          <option value="Genius" ${genius ? "selected" : ""}>Genius — 6-section gauntlet</option>
        </select>
      </label>
      <label>
        <span>Rounds</span>
        ${genius
          ? `<input type="hidden" name="roundCount" value="30" /><div class="locked-setting">30 · fixed</div>`
          : `<select name="roundCount">${[5, 10, 15, 20, 30].map((value) => `<option value="${value}" ${state.room.settings.roundCount === value ? "selected" : ""}>${value}</option>`).join("")}</select>`}
      </label>
      <label>
        <span>Pacing</span>
        <select name="pacingMode">
          ${[
            ["Relaxed", "Relaxed · 20s"],
            ["Normal", "Normal · 15s"],
            ["Fast", "Fast · 10s"]
          ].map(([value, label]) => `<option value="${value}" ${currentPacingMode() === value ? "selected" : ""}>${label}</option>`).join("")}
        </select>
      </label>
      <label class="wide-field">
        <span>Category mode</span>
        ${genius
          ? `<input type="hidden" name="categoryMode" value="${escapeAttr(state.room.settings.categoryMode)}" /><div class="locked-setting">All six Genius categories</div>`
          : `<select name="categoryMode">${CATEGORY_MODES.map((mode) => `<option value="${escapeAttr(mode)}" ${state.room.settings.categoryMode === mode ? "selected" : ""}>${escapeHtml(mode)}</option>`).join("")}</select>`}
      </label>
      <button class="primary-button wide-field" id="start-game" type="button" ${!canStartFromLobby() ? "disabled" : ""}>${genius ? "Enter the Genius Gauntlet" : "Start Game"}</button>
    </form>
  `;
}

function renderInstallCard(context = "landing") {
  if (isStandaloneMode() || state.installDismissed) return "";
  const showNativeInstall = state.canInstall && state.installPrompt;
  return `
    <section class="install-card">
      <div>
        <p class="eyebrow">Phone app</p>
        <h3>${showNativeInstall ? "Install Atwix Trivia." : "Save it to your home screen."}</h3>
        <p>${showNativeInstall ? "Open it like a normal app when the room starts." : "On iPhone, tap Share, then Add to Home Screen."}</p>
      </div>
      <div class="install-actions">
        ${showNativeInstall ? `<button class="secondary-button" id="install-app">Install App</button>` : ""}
        <button class="ghost-button" id="dismiss-install">${context === "lobby" ? "Later" : "Not now"}</button>
      </div>
    </section>
  `;
}

function renderCountdown() {
  const question = getCurrentQuestion();
  const count = Math.max(1, Math.ceil((state.room.currentQuestionStartedAt - Date.now()) / 1000));
  const section = geniusSectionInfo();
  const geniusCopy = section
    ? `<p class="section-counter">Section ${section.number} of ${GENIUS_CATEGORIES.length} · Question ${section.questionNumber} of 5</p>
       <h2>${section.questionNumber === 1 ? escapeHtml(section.category) : "Next Genius question"}</h2>`
    : `<h2>${escapeHtml(getPhrase("countdown", roundPhraseKey()))}</h2>`;
  return `
    <section class="countdown-panel">
      <p class="eyebrow">${section && section.questionNumber === 1 ? "New section unlocked" : escapeHtml(question.category)}</p>
      <div class="countdown-number">${count}</div>
      ${geniusCopy}
    </section>
  `;
}

function renderQuestion() {
  const question = getCurrentQuestion();
  const ownAnswer = getOwnCurrentAnswer();
  const selected = ownAnswer?.choiceIndex;
  const locked = Boolean(ownAnswer || state.pendingAnswerKey === answerKey());
  const remaining = Math.max(0, state.room.currentQuestionEndsAt - Date.now());
  const total = state.room.settings.timerSeconds * 1000;
  const percent = Math.max(0, Math.min(100, (remaining / total) * 100));
  const secondsLeft = Math.max(0, Math.ceil(remaining / 1000));
  const answeredCount = Object.keys(state.room.answers?.[getCurrentQuestionId(state.room)] || {}).length;
  const section = geniusSectionInfo();
  return `
    <div class="progress-row">
      <span>${section ? `Section ${section.number}/${GENIUS_CATEGORIES.length} · Question ${section.questionNumber}/5` : `Round ${state.room.currentRoundIndex + 1} of ${totalRounds()}`}</span>
      <strong class="timer-count">${secondsLeft}s left</strong>
    </div>
    <div class="progress-row mini-row">
      <span>${escapeHtml(question.category)}</span>
      <span>${answeredCount}/${state.room.players.length} answered</span>
    </div>
    <div class="timer-track"><span style="width:${percent}%"></span></div>
    <article class="question-card">
      <p class="card-category">${isGeniusMode() ? "Genius · double points" : escapeHtml(question.difficulty)} · ${escapeHtml(question.category)}</p>
      ${renderQuestionMedia(question)}
      <h2>${escapeHtml(displayQuestionText(question))}</h2>
    </article>
    <section class="answer-grid">
      ${question.choices.map((choice, index) => `
        <button class="answer-option ${selected === index ? "selected" : ""}" data-choice="${index}" ${locked ? "disabled" : ""}>
          <strong>${String.fromCharCode(65 + index)}</strong>
          <span>${escapeHtml(choice)}</span>
        </button>
      `).join("")}
    </section>
    ${locked
      ? `<p class="inline-note">${escapeHtml(getPhrase("answerLocked", answerKey()))} ${escapeHtml(getPhrase("waitingAfterAnswer", roundPhraseKey()))} ${answeredCount}/${state.room.players.length} answered.</p>`
      : `<p class="helper">${escapeHtml(getPhrase("questionHelper", roundPhraseKey()))}</p>`}
  `;
}

function renderQuestionMedia(question) {
  if (question.mediaType !== "image" || !question.imageUrl) return "";
  const isExternal = /^https?:\/\//.test(question.imageUrl);
  const imageSrc = isExternal ? question.imageUrl : `${question.imageUrl}${question.imageUrl.includes("?") ? "&" : "?"}v=visual-card-3`;
  const mediaClass = question.imageUrl.includes("cdn.simpleicons.org")
    ? "logo-media"
    : question.imageUrl.includes("flagcdn.com")
      ? "flag-media"
      : "photo-media";
  return `
    <figure class="question-media ${mediaClass}">
      <img src="${escapeAttr(imageSrc)}" alt="${escapeAttr(question.imageAlt || question.question)}" loading="eager" decoding="sync" fetchpriority="high" onerror="this.closest('.question-media').classList.add('media-failed')" />
      <figcaption>${escapeHtml(question.imageCaption || "Visual clue")}</figcaption>
      <div class="media-fallback" aria-hidden="true">Image clue unavailable</div>
    </figure>
  `;
}

function renderReveal() {
  const question = getCurrentQuestion();
  const result = getRoundResult(state.room);
  const playerResult = getPlayerResult(state.room, state.currentPlayer.id);
  const revealStory = getRevealStory(result, playerResult);
  const fastest = playerName(result?.fastestCorrectPlayerId);
  const totalAnswers = Math.max(1, result?.answerCounts?.reduce((sum, count) => sum + count, 0) || 0);
  const section = geniusSectionInfo();
  return `
    <div class="progress-row">
      <span>${section ? `Genius ${section.number}.${section.questionNumber}` : escapeHtml(revealStory.kicker)}</span>
      <span>${escapeHtml(question.category)}</span>
    </div>
    <section class="reveal-answer ${playerResult?.isCorrect ? "correct" : "wrong"}">
      <p>${escapeHtml(revealStory.headline)}</p>
      <h2>${escapeHtml(result.correctAnswer)}</h2>
      <span>${escapeHtml(`${result.explanation} ${revealStory.body}`.trim())}</span>
    </section>
    <section class="panel">
      <div class="section-title">
        <h3>Answer split</h3>
        <span>${Math.round((result.answerCounts[result.correctIndex] / totalAnswers) * 100)}% correct</span>
      </div>
      <div class="answer-bars">
        ${question.choices.map((choice, index) => {
          const count = result.answerCounts[index] || 0;
          const pct = Math.round((count / totalAnswers) * 100);
          return `<div class="answer-bar ${index === result.correctIndex ? "is-correct" : ""}">
            <span>${String.fromCharCode(65 + index)} · ${escapeHtml(choice)}</span>
            <strong>${pct}%</strong>
          </div>`;
        }).join("")}
      </div>
    </section>
	    <section class="panel">
	      <div class="section-title">
	        <h3>Player answers</h3>
	        <span>${fastest ? `Fastest: ${escapeHtml(fastest)}` : "No correct answers"}</span>
	      </div>
      <div class="points-list">
        ${result.playerResults.map((item) => `
          <div>
            <span>
              ${escapeHtml(playerName(item.playerId))}
              <small>${escapeHtml(playerAnswerLabel(question, item))}</small>
              ${item.streakBonus ? ` <small>Streak +${item.streakBonus}</small>` : ""}
            </span>
            <strong>${item.points}</strong>
          </div>
        `).join("")}
	      </div>
	      ${isCurrentHost() ? `<button class="primary-button wide" id="show-leaderboard">Show Leaderboard</button>` : `<p class="helper">${escapeHtml(getPhrase("waitingForHost", `reveal:${roundPhraseKey()}`))}</p>`}
	    </section>
	    <section class="panel">
	      <div class="section-title">
	        <h3>Question report</h3>
	        <span>${hasReportedQuestion() ? "Sent" : "Optional"}</span>
	      </div>
	      <p class="helper">${hasReportedQuestion() ? "Thanks. This question is marked for review." : "Flag a question if something felt off."}</p>
	      <div class="report-actions">
	        <button class="ghost-button" data-report="too_easy" ${hasReportedQuestion("too_easy") ? "disabled" : ""}>Too easy</button>
	        <button class="ghost-button" data-report="wrong_answer" ${hasReportedQuestion("wrong_answer") ? "disabled" : ""}>Wrong answer</button>
	        <button class="ghost-button" data-report="repeated" ${hasReportedQuestion("repeated") ? "disabled" : ""}>Repeated</button>
	        <button class="ghost-button" data-report="unclear" ${hasReportedQuestion("unclear") ? "disabled" : ""}>Unclear</button>
	      </div>
	    </section>
	  `;
	}

function renderLeaderboard() {
  const leaderboard = state.room.lastLeaderboard || [];
  const isLastRound = state.room.currentRoundIndex >= totalRounds() - 1;
  const story = getLeaderboardStory(leaderboard);
  const ready = state.room.nextReady || {};
  const readyCount = state.room.players.filter((player) => ready[player.id]).length;
  const currentReady = Boolean(ready[state.currentPlayer.id]);
  const section = geniusSectionInfo();
  const sectionComplete = Boolean(section && section.questionNumber === 5);
  const nextCategory = sectionComplete ? GENIUS_CATEGORIES[section.number] : "";
  const displayedStory = sectionComplete
    ? {
        headline: `${section.category} conquered.`,
        body: nextCategory ? `Section ${section.number} is sealed. Next arena: ${nextCategory}.` : "All six domains are complete. One final crown remains."
      }
    : story;
  return `
    <section class="summary-hero">
      <p class="eyebrow">${sectionComplete ? `Section ${section.number} complete` : "Leaderboard"}</p>
      <h1>${escapeHtml(displayedStory.headline)}</h1>
      <p>${escapeHtml(displayedStory.body)}</p>
    </section>
    <section class="leaderboard-list">
      ${leaderboard.map((entry) => renderLeaderboardEntry(entry)).join("")}
    </section>
    <section class="panel">
      <div class="section-title">
        <h3>${isLastRound ? "Final reveal check" : sectionComplete ? "Next section check" : "Next question check"}</h3>
        <span>${readyCount}/${state.room.players.length} ready</span>
      </div>
      <p class="helper">${currentReady ? "You are ready. Waiting for the rest of the room." : "Everyone taps ready, then the next screen starts together."}</p>
      <div class="player-list ready-list">
        ${state.room.players.map((player) => `
          <div class="player-pill">
            <span>${escapeHtml(player.displayName)}${player.id === state.currentPlayer.id ? " <small>You</small>" : ""}</span>
            <strong>${ready[player.id] ? "Ready" : "Not yet"}</strong>
          </div>
        `).join("")}
      </div>
    </section>
    <button class="primary-button wide" id="next-question" ${currentReady ? "disabled" : ""}>${currentReady ? "Ready locked" : isLastRound ? "Reveal the Genius" : sectionComplete ? `Enter ${escapeHtml(nextCategory)}` : "Ready for Next Question"}</button>
  `;
}

function renderFinal() {
  const leaderboard = state.room.lastLeaderboard || [];
  const winner = leaderboard[0];
  const awards = state.room.finalAwards || {};
  const winnerLine = winner
    ? `${winner.displayName} takes the ${isGeniusMode() ? "Genius Crown" : "crown"} with ${winner.totalPoints} points.`
    : getPhrase("final", state.room.code);
  return `
    <section class="summary-hero final-hero">
      ${renderConfetti()}
      <p class="eyebrow">${isGeniusMode() ? "The gauntlet is complete" : "Final results"}</p>
      <h1>${winner ? `${escapeHtml(winner.displayName)} ${isGeniusMode() ? "is the Genius!" : "wins!"}` : "Game over!"}</h1>
      <p>${escapeHtml(winnerLine)}</p>
      <small>${state.room.historySaved ? "Career and rivalry records updated." : "Career record will retry when the history service is available."}</small>
    </section>
    <section class="leaderboard-list">
      ${leaderboard.map((entry) => renderLeaderboardEntry(entry)).join("")}
    </section>
    <section class="panel">
      <div class="section-title">
        <h3>Fun awards</h3>
        <span>Group chat material</span>
      </div>
	      <div class="awards-grid">
	        ${renderAwardCards(awards)}
	      </div>
	    </section>
    <div class="summary-actions">
      ${isCurrentHost() ? `<button class="secondary-button" id="play-again">Play Again</button>` : ""}
      <button class="primary-button" data-view="create">New Room</button>
    </div>
  `;
}

function renderLeaderboardEntry(entry) {
  const movement = entry.rankChange > 0 ? `▲ ${entry.rankChange}` : entry.rankChange < 0 ? `▼ ${Math.abs(entry.rankChange)}` : "–";
  return `
    <article class="leaderboard-card rank-${entry.rank}">
      <strong>#${entry.rank}</strong>
      <div>
        <h3>${escapeHtml(entry.displayName)}</h3>
        <p>${entry.correctAnswers} correct · streak ${entry.currentStreak}</p>
      </div>
      <span>${movement}</span>
      <b>${entry.totalPoints}</b>
    </article>
  `;
}

function getLeaderboardStory(leaderboard) {
  const result = getRoundResult(state.room);
  const leader = leaderboard[0];
  const fastestName = playerName(result?.fastestCorrectPlayerId);
  const correctResults = result?.playerResults?.filter((item) => item.isCorrect) || [];
  const biggestClimber = [...leaderboard].filter((entry) => entry.rankChange > 0).sort((a, b) => b.rankChange - a.rankChange)[0];
  const topRound = [...(result?.playerResults || [])].sort((a, b) => b.points - a.points)[0];
  const topRoundName = topRound ? playerName(topRound.playerId) : "";

  if (!correctResults.length) {
    return {
      headline: "Full room trap.",
      body: "Nobody got it right, so every streak just hit the floor."
    };
  }

  if (leader?.previousRank && leader.previousRank > 1) {
    return {
      headline: "The crown moved.",
      body: `${leader.displayName} jumped from #${leader.previousRank} to #1. That changes the room.`
    };
  }

  if (biggestClimber && biggestClimber.rankChange >= 2) {
    return {
      headline: "Comeback with receipts.",
      body: `${biggestClimber.displayName} climbed ${biggestClimber.rankChange} places in one round.`
    };
  }

  if (topRound?.points >= 150 && topRoundName) {
    return {
      headline: "Perfect hit.",
      body: `${topRoundName} took ${topRound.points} points. Fast, correct, slightly annoying.`
    };
  }

  if (leader?.currentStreak >= 3) {
    return {
      headline: "Protect that streak.",
      body: `${leader.displayName} is leading with ${leader.currentStreak} correct in a row.`
    };
  }

  if (fastestName) {
    return {
      headline: "Speed won the argument.",
      body: `${fastestName} got the fastest correct answer this round.`
    };
  }

  return {
    headline: "The table shifts.",
    body: leader ? `${leader.displayName} is still the target at ${leader.totalPoints} points.` : "Nobody is safe for long."
  };
}

function getRevealStory(result, playerResult) {
  const correctResults = result?.playerResults?.filter((item) => item.isCorrect) || [];
  const totalPlayers = result?.playerResults?.length || state.room.players.length || 1;
  const fastestName = playerName(result?.fastestCorrectPlayerId);

  if (!playerResult || playerResult.choiceIndex === null || playerResult.choiceIndex === undefined) {
    return {
      kicker: "Clock won",
      headline: "No answer locked.",
      body: "The timer took that one."
    };
  }

  if (!correctResults.length) {
    return {
      kicker: "Room trap",
      headline: "Nobody got away clean.",
      body: "Every streak reset together."
    };
  }

  if (playerResult.isCorrect && result.fastestCorrectPlayerId === state.currentPlayer.id) {
    return {
      kicker: "Fastest correct",
      headline: "You hit first.",
      body: `Fastest in the room${playerResult.speedBonus ? `, with +${playerResult.speedBonus} speed` : ""}.`
    };
  }

  if (playerResult.isCorrect && playerResult.streakBonus) {
    return {
      kicker: "Streak paid",
      headline: `Correct, plus streak money.`,
      body: `Your streak bonus added +${playerResult.streakBonus}.`
    };
  }

  if (playerResult.isCorrect && correctResults.length <= Math.max(1, Math.floor(totalPlayers / 2))) {
    return {
      kicker: "Minority win",
      headline: "You were on the right side.",
      body: `${correctResults.length}/${totalPlayers} players got it.`
    };
  }

  if (playerResult.isCorrect) {
    return {
      kicker: "Clean points",
      headline: "Correct answer locked.",
      body: fastestName ? `${fastestName} was fastest this time.` : "Speed still mattered."
    };
  }

  const chosenCount = result.answerCounts?.[playerResult.choiceIndex] || 0;
  const correctCount = result.answerCounts?.[result.correctIndex] || 0;
  if (chosenCount > correctCount && chosenCount > 1) {
    return {
      kicker: "Crowd trap",
      headline: "Popular answer. Still wrong.",
      body: `${chosenCount} players fell for the same option.`
    };
  }

  return {
    kicker: "Missed it",
    headline: "Bold choice, wrong turn.",
    body: fastestName ? `${fastestName} was fastest on the correct answer.` : "Next round is the comeback round."
  };
}

function renderConfetti() {
  return `
    <div class="confetti" aria-hidden="true">
      ${Array.from({ length: 44 }, (_, index) => `<span style="--i:${index}; --x:${(index * 37) % 100}; --delay:${(index % 11) * 0.09}s; --spin:${index % 2 ? 1 : -1};"></span>`).join("")}
    </div>
  `;
}

function renderAward(label, playerId) {
  return `<div class="award"><span>${escapeHtml(label)}</span><strong>${escapeHtml(playerName(playerId) || "—")}</strong></div>`;
}

function renderAwardCards(awards) {
  const cards = awards.cards || [
    { label: "Winner", playerId: awards.winnerId, detail: "Top score." },
    { label: "Fastest Answer", playerId: awards.fastestThinkerId, detail: "Fastest correct answers." },
    { label: "Biggest Comeback", playerId: awards.bestComebackId, detail: "Best single-round jump." },
    { label: "Longest Streak", playerId: awards.longestStreakId, detail: "Most answers in a row." },
    { label: "Most Chaotic Guess", playerId: awards.mostConfidentlyWrongId, detail: "Most bold misses." }
  ];
  return cards.map((award) => `
    <div class="award detailed-award">
      <span>${escapeHtml(award.label)}</span>
      <strong>${escapeHtml(playerName(award.playerId) || "—")}</strong>
      <small>${escapeHtml(award.detail || "")}</small>
    </div>
  `).join("");
}

async function consumeAuthCallback() {
  const hash = new URLSearchParams(window.location.hash.replace(/^#/, ""));
  const accessToken = hash.get("access_token");
  const refreshToken = hash.get("refresh_token");
  if (!accessToken || !refreshToken) return;
  try {
    const result = await exchangeAuthTokens(accessToken, refreshToken);
    state.account = result.account;
    state.authView = params.get("auth") === "reset" || hash.get("type") === "recovery" ? "reset-password" : "sign-in";
  } catch (error) {
    state.error = error.message;
  } finally {
    if (state.authView !== "reset-password") clearAuthFromUrl();
  }
}

async function handleSignIn(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  await safely(async () => {
    state.loading = true;
    render();
    const result = await signInAccount(form.get("email"), form.get("password"));
    state.account = result.account;
    state.playerId = result.account.id;
    state.authMessage = "";
    state.view = "landing";
    if (state.joinCode) {
      const room = await readRoom(state.joinCode);
      if (room) {
        state.room = room;
        state.currentPlayer = recoverPlayer(room, state.playerId);
        state.view = state.currentPlayer ? "room" : "join";
        connectRoom(room.code);
      }
    }
  });
  state.loading = false;
  render();
}

async function handleSignUp(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  await safely(async () => {
    state.loading = true;
    render();
    const result = await signUpAccount(form.get("email"), form.get("password"), form.get("displayName"), authReturnTo());
    if (result.account) {
      state.account = result.account;
      state.playerId = result.account.id;
      state.view = "landing";
    } else {
      state.authView = "check-email";
      state.authMessage = result.message;
    }
  });
  state.loading = false;
  render();
}

async function handleForgotPassword(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  await safely(async () => {
    const result = await requestPasswordReset(form.get("email"), authReturnTo());
    state.authMessage = result.message;
    state.authView = "sign-in";
  });
  render();
}

async function handleResetPassword(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  await safely(async () => {
    const result = await updateAccountPassword(form.get("password"));
    state.authMessage = result.message;
    state.authView = "sign-in";
    const session = await readSession();
    state.account = session.account;
    state.playerId = session.account?.id || "";
    state.view = "landing";
    clearAuthFromUrl();
  });
  render();
}

async function handleSignOut() {
  await safely(async () => {
    await signOutAccount();
    state.unsubscribe?.();
    clearInterval(state.timer);
    stopAllAudio();
    state.account = null;
    state.accountSummary = null;
    state.room = null;
    state.currentPlayer = null;
    state.playerId = "";
    state.view = "landing";
    state.authView = "sign-in";
    history.replaceState({}, "", window.location.pathname);
  });
  render();
}

async function loadAccountSummary() {
  try {
    state.accountSummary = await readAccountSummary();
    state.account = state.accountSummary.account;
  } catch (error) {
    state.error = error.message;
  }
}

function authReturnTo() {
  const target = new URL(window.location.href);
  target.hash = "";
  target.searchParams.delete("auth");
  target.searchParams.delete("player");
  return `${target.pathname}${target.search}`;
}

function clearAuthFromUrl() {
  const target = new URL(window.location.href);
  target.hash = "";
  target.searchParams.delete("auth");
  target.searchParams.delete("code");
  target.searchParams.delete("token_hash");
  target.searchParams.delete("type");
  history.replaceState({}, "", `${target.pathname}${target.search}`);
}

function bindActions() {
  document.querySelectorAll("[data-auth-view]").forEach((button) => {
    button.addEventListener("click", () => {
      state.authView = button.dataset.authView;
      state.authMessage = "";
      state.error = "";
      render();
    });
  });
  document.querySelector("#sign-in-form")?.addEventListener("submit", handleSignIn);
  document.querySelector("#sign-up-form")?.addEventListener("submit", handleSignUp);
  document.querySelector("#forgot-form")?.addEventListener("submit", handleForgotPassword);
  document.querySelector("#reset-password-form")?.addEventListener("submit", handleResetPassword);
  document.querySelector("#sign-out")?.addEventListener("click", handleSignOut);

  document.querySelectorAll("[data-view]").forEach((button) => {
    button.addEventListener("click", async () => {
      if (button.dataset.createMode) state.createMode = button.dataset.createMode;
      state.unsubscribe?.();
      clearInterval(state.timer);
      state.view = button.dataset.view;
      state.room = null;
      state.currentPlayer = null;
      state.playerId = state.account?.id || "";
      state.error = "";
	      state.pendingAnswerKey = "";
	      state.localChoices.clear();
	      state.audioEvents.clear();
	      state.connection = "idle";
	      stopAllAudio();
      history.replaceState({}, "", window.location.pathname);
      if (state.view === "profile") await loadAccountSummary();
      render();
    });
  });

  document.querySelectorAll("[data-copy]").forEach((button) => {
    button.addEventListener("click", () => copyText(button.dataset.copy, "Invite link copied."));
  });

  document.querySelector("#create-form")?.addEventListener("submit", handleCreate);
  document.querySelectorAll("#create-form input[name='gameMode']").forEach((input) => {
    input.addEventListener("change", (event) => {
      state.createMode = event.target.value;
      render();
    });
  });
  document.querySelector("#join-form")?.addEventListener("submit", handleJoin);
  document.querySelector("#join-form input[name='roomCode']")?.addEventListener("input", (event) => {
    state.joinCode = event.target.value.toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 5);
    event.target.value = state.joinCode;
  });

	  document.querySelector("#settings-form")?.addEventListener("change", handleSettingsChange);
	  document.querySelector("#lobby-ready")?.addEventListener("click", () => safely(async () => {
	    state.room = await setLobbyReady(state.room.code, state.currentPlayer.id, true);
	    showToast("Ready locked.");
	    render();
	  }));
	  document.querySelector("#claim-host")?.addEventListener("click", () => safely(async () => {
	    state.room = await transferHost(state.room.code, state.currentPlayer.id);
	    showToast("You are host now.");
	    render();
	  }));
	  document.querySelectorAll("[data-transfer-host]").forEach((button) => {
	    button.addEventListener("click", () => safely(async () => {
	      state.room = await transferHost(state.room.code, state.currentPlayer.id, button.dataset.transferHost);
	      showToast("Host handed off.");
	      render();
	    }));
	  });
	  document.querySelector("#start-game")?.addEventListener("click", () => safely(async () => {
	    state.room = await startGame(state.room.code, state.currentPlayer.id);
	    render();
  }));
  document.querySelectorAll("[data-choice]").forEach((button) => {
    button.addEventListener("click", () => handleAnswerSelect(Number(button.dataset.choice)));
  });
	  document.querySelector("#show-leaderboard")?.addEventListener("click", () => safely(async () => {
	    state.room = await showLeaderboard(state.room.code, state.currentPlayer.id);
	    render();
	  }));
	  document.querySelectorAll("[data-report]").forEach((button) => {
	    button.addEventListener("click", () => safely(async () => {
	      state.room = await reportQuestion(state.room.code, state.currentPlayer.id, getCurrentQuestionId(state.room), button.dataset.report);
	      showToast("Question report sent.");
	      render();
	    }));
	  });
  document.querySelector("#next-question")?.addEventListener("click", () => safely(async () => {
    state.room = await nextQuestion(state.room.code, state.currentPlayer.id);
    render();
  }));
  document.querySelector("#play-again")?.addEventListener("click", () => safely(async () => {
    state.room = await playAgain(state.room.code, state.currentPlayer.id);
    state.audioEvents.clear();
    stopAllAudio();
    render();
  }));
  document.querySelector("#share-button")?.addEventListener("click", handleShare);
  document.querySelector("#sound-toggle")?.addEventListener("click", handleSoundToggle);
  document.querySelector("#music-toggle")?.addEventListener("click", handleMusicToggle);
  document.querySelector("#volume-slider")?.addEventListener("input", handleVolumeChange);
  document.querySelector("#install-app")?.addEventListener("click", handleInstallApp);
  document.querySelector("#dismiss-install")?.addEventListener("click", () => {
    state.installDismissed = true;
    localStorage.setItem("room-rush-install-dismissed", "true");
    render();
  });
}

async function handleCreate(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  const selectedMode = String(form.get("gameMode") || state.createMode || "Classic");
  await safely(async () => {
    state.loading = true;
    render();
    const result = await createRoom();
    state.room = selectedMode === "Genius"
      ? await updateSettings(result.room.code, result.player.id, {
          gameMode: "Genius",
          roundCount: 30,
          pacingMode: result.room.settings.pacingMode || "Normal",
          categoryMode: result.room.settings.categoryMode
        })
      : result.room;
    state.currentPlayer = result.player;
    state.playerId = result.player.id;
    state.view = "room";
    history.replaceState({}, "", playerUrl(state.room.code));
    connectRoom(state.room.code);
  });
  state.loading = false;
  render();
}

async function handleJoin(event) {
  event.preventDefault();
  const form = new FormData(event.currentTarget);
  await safely(async () => {
    state.loading = true;
    render();
    const result = await joinRoom(form.get("roomCode"));
    state.room = result.room;
    state.currentPlayer = result.player;
    state.playerId = result.player.id;
    state.view = "room";
    state.joinCode = state.room.code;
    history.replaceState({}, "", playerUrl(state.room.code));
    connectRoom(state.room.code);
  });
  state.loading = false;
  render();
}

async function handleSettingsChange(event) {
  const form = new FormData(event.currentTarget);
  await safely(async () => {
	    state.room = await updateSettings(state.room.code, state.currentPlayer.id, {
	      gameMode: form.get("gameMode"),
	      roundCount: Number(form.get("roundCount")),
	      pacingMode: form.get("pacingMode"),
	      categoryMode: form.get("categoryMode")
	    });
    render();
  });
}

async function handleShare() {
  if (navigator.share) {
    try {
      await navigator.share({
	        title: "Atwix Trivia",
	        text: `Join my Atwix Trivia room ${state.room.code}.`,
	        url: state.room.inviteUrl
      });
    } catch {
      showToast("Share canceled.");
    }
  } else {
    await copyText(state.room.inviteUrl, "Invite link copied.");
  }
}

async function handleSoundToggle() {
  const audio = getAudioSettings();
  if (!audio.unlocked) await enableAudio();
  else setSoundEnabled(!audio.soundOn);
  if (!getAudioSettings().soundOn) stopAllAudio();
  render();
}

function handleMusicToggle() {
  const audio = getAudioSettings();
  setMusicEnabled(!audio.musicOn);
  render();
}

function handleVolumeChange(event) {
  setMasterVolume(event.target.value);
}

async function handleInstallApp() {
  if (!state.installPrompt) return;
  const prompt = state.installPrompt;
  state.installPrompt = null;
  state.canInstall = false;
  prompt.prompt();
  const choice = await prompt.userChoice.catch(() => ({ outcome: "dismissed" }));
  if (choice.outcome === "accepted") {
    state.installDismissed = true;
    localStorage.setItem("room-rush-install-dismissed", "true");
  }
  render();
}

async function handleAnswerSelect(choiceIndex) {
  const key = answerKey();
  if (!key || getOwnCurrentAnswer() || state.pendingAnswerKey === key) return;

  state.localChoices.set(key, choiceIndex);
  state.pendingAnswerKey = key;
  state.error = "";
  playSound("answerLock");
  render();

  try {
    state.room = await submitAnswer(state.room.code, state.currentPlayer.id, choiceIndex);
  } catch (error) {
    const message = error.message || "Something went wrong.";
    state.error = message;
    if (!/Answer locked/i.test(message)) {
      state.localChoices.delete(key);
    }
  } finally {
    if (state.pendingAnswerKey === key) state.pendingAnswerKey = "";
    render();
  }
}

function connectRoom(code) {
  state.unsubscribe?.();
  state.connection = "connecting";
  state.unsubscribe = subscribeToRoom(code, state.currentPlayer?.id, (room) => {
    const previousStatus = state.room?.status || "";
    state.room = room;
    state.currentPlayer = recoverPlayer(room, state.currentPlayer?.id) || state.currentPlayer;
    if (room.status !== "question") state.pendingAnswerKey = "";
    if (room.status === "lobby" && previousStatus && previousStatus !== "lobby") {
      state.audioEvents.clear();
      stopAllAudio();
    }
    render();
    handleRoomAudio();
  }, (connection) => {
    const wasReconnecting = state.connection === "reconnecting";
    state.connection = connection;
    if (connection === "live" && wasReconnecting) showToast("Reconnected to the room.");
    render();
  });

  clearInterval(state.timer);
  state.timer = setInterval(async () => {
    if (!state.room) return;
    if (state.room.status === "question") {
      if (Date.now() >= state.room.currentQuestionEndsAt) {
        await safely(async () => {
          state.room = await tickRoom(state.room.code);
        });
      }
      render();
      handleRoomAudio();
    }
  }, 500);
}

function handleRoomAudio() {
  const audio = getAudioSettings();
  if (!audio.unlocked || !audio.soundOn || !state.room || !state.currentPlayer) return;

  if (state.room.status === "question" && Date.now() < state.room.currentQuestionStartedAt) {
    const count = Math.max(1, Math.ceil((state.room.currentQuestionStartedAt - Date.now()) / 1000));
    triggerAudioOnce(`${roundAudioKey()}:countdown:${count}`, "countdown");
    return;
  }

  if (state.room.status === "reveal") {
    triggerAudioOnce(`${roundAudioKey()}:reveal`, "reveal");
    const playerResult = getPlayerResult(state.room, state.currentPlayer.id);
    if (playerResult) {
      triggerAudioOnce(
        `${roundAudioKey()}:result:${state.currentPlayer.id}`,
        playerResult.isCorrect ? "correct" : "wrong"
      );
    }
    return;
  }

  if (state.room.status === "leaderboard") {
    triggerAudioOnce(`${roundAudioKey()}:leaderboard`, "leaderboard");
    return;
  }

  if (state.room.status === "finished") {
    triggerAudioOnce(`${state.room.code}:winner:${state.room.selectedQuestionIds.join("-")}`, "winner");
  }
}

function triggerAudioOnce(key, soundName) {
  if (state.audioEvents.has(key)) return;
  state.audioEvents.add(key);
  playSound(soundName);
}

function getCurrentQuestion() {
  return QUESTION_BY_ID[getCurrentQuestionId(state.room)];
}

function displayQuestionText(question) {
  return String(question?.question || "")
    .replace(/^(Quick one|Speed round|No overthinking|Party check|Protect your streak|Fast fingers|For the bragging rights|Room check):\s*/i, "");
}

function getOwnCurrentAnswer() {
  const answer = getCurrentAnswer(state.room, state.currentPlayer?.id);
  const key = answerKey();
  if (!answer && !state.localChoices.has(key)) return null;
  return {
    ...(answer || {}),
    choiceIndex: state.localChoices.has(key) ? state.localChoices.get(key) : answer?.choiceIndex
  };
}

function answerKey(room = state.room, playerId = state.currentPlayer?.id) {
  const questionId = getCurrentQuestionId(room);
  if (!room?.code || !playerId || !questionId) return "";
  return `${room.code}:${room.currentRoundIndex}:${questionId}:${playerId}`;
}

function roundAudioKey() {
  return `${state.room.code}:${state.room.currentRoundIndex}:${getCurrentQuestionId(state.room)}`;
}

function roundPhraseKey() {
  return roundAudioKey();
}

function totalRounds() {
  return state.room?.selectedQuestionIds?.length || state.room?.settings?.roundCount || 0;
}

function isGeniusMode(room = state.room) {
  return room?.settings?.gameMode === "Genius";
}

function geniusSectionInfo(room = state.room) {
  if (!isGeniusMode(room)) return null;
  const roundIndex = room?.currentRoundIndex || 0;
  const sectionIndex = Math.floor(roundIndex / 5);
  return {
    index: sectionIndex,
    number: sectionIndex + 1,
    questionNumber: (roundIndex % 5) + 1,
    category: GENIUS_CATEGORIES[sectionIndex] || getCurrentQuestion()?.category || "Genius"
  };
}

function playerAnswerLabel(question, result) {
  if (result.choiceIndex === null || result.choiceIndex === undefined) return "No answer";
  const letter = String.fromCharCode(65 + result.choiceIndex);
  return `${letter}: ${question.choices[result.choiceIndex]}`;
}

function isCurrentHost() {
  return state.currentPlayer?.id === state.room?.hostId;
}

function isPlayerOnline(playerId) {
  return Boolean(state.room?.presence?.[playerId]?.connected);
}

function canStartFromLobby() {
  if (!state.room || state.room.players.length < 2) return false;
  const ready = state.room.lobbyReady || {};
  return state.room.players.every((player) => ready[player.id]);
}

function currentPacingMode() {
  if (state.room?.settings?.pacingMode) return state.room.settings.pacingMode;
  const seconds = state.room?.settings?.timerSeconds;
  if (seconds >= 20) return "Relaxed";
  if (seconds <= 10) return "Fast";
  return "Normal";
}

function hasReportedQuestion(reason = null) {
  const questionId = getCurrentQuestionId(state.room);
  return Boolean(state.room?.questionReports?.some((report) => {
    if (report.playerId !== state.currentPlayer?.id || report.questionId !== questionId) return false;
    return reason ? report.reason === reason : true;
  }));
}

function playerName(playerId) {
  return state.room?.players.find((player) => player.id === playerId)?.displayName || "";
}

function isStandaloneMode() {
  return window.matchMedia("(display-mode: standalone)").matches || window.navigator.standalone === true;
}

function registerServiceWorker() {
  if (!("serviceWorker" in navigator)) return;
  window.addEventListener("load", () => {
    navigator.serviceWorker.register("/sw.js").catch(() => {});
  }, { once: true });
}

async function safely(action) {
  try {
    state.error = "";
    await action();
  } catch (error) {
    state.error = error.message || "Something went wrong.";
  }
}

async function copyText(text, message) {
  try {
    await navigator.clipboard.writeText(text);
    showToast(message);
  } catch {
    showToast("Copy did not work in this browser.");
  }
}

function showToast(message) {
  toast.textContent = message;
  toast.classList.add("show");
  setTimeout(() => toast.classList.remove("show"), 1800);
}

function playerUrl(code) {
  return `?room=${encodeURIComponent(code)}`;
}

function formatHistoryDate(value) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "recently";
  return new Intl.DateTimeFormat(undefined, { month: "short", day: "numeric", year: "numeric" }).format(date);
}

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function escapeAttr(value) {
  return escapeHtml(value).replaceAll("`", "&#096;");
}

